await page.waitForTimeout(1000);
var pageInfo = await page.evaluate(() => ({
  title: document.title,
  bodyText: document.body.innerText.slice(0, 500),
  hasCanvas: !!document.querySelector('canvas'),
  terminalHidden: document.querySelector('#terminal')?.classList.contains('hidden'),
  webglRenderer: !!document.querySelector('canvas')?.getContext('webgl2') || !!document.querySelector('canvas')?.getContext('webgl'),
  overlay: !!document.querySelector('.vite-error-overlay'),
}));
async function measure(label, setupCss) {
  if (setupCss) await page.addStyleTag({ content: setupCss });
  return await page.evaluate(async (label) => {
    const samples = [];
    let last;
    const start = performance.now();
    await new Promise(resolve => {
      function step(now) {
        if (last != null) samples.push(now - last);
        last = now;
        if (now - start < 2500) requestAnimationFrame(step);
        else resolve();
      }
      requestAnimationFrame(step);
    });
    samples.sort((a, b) => a - b);
    const avg = samples.reduce((a, b) => a + b, 0) / samples.length;
    const p95 = samples[Math.floor(samples.length * 0.95)] || 0;
    const p99 = samples[Math.floor(samples.length * 0.99)] || 0;
    const over25 = samples.filter(v => v > 25).length;
    const over33 = samples.filter(v => v > 33).length;
    return { label, frames: samples.length, avg: Number(avg.toFixed(2)), p95: Number(p95.toFixed(2)), p99: Number(p99.toFixed(2)), over25, over33 };
  }, label);
}
var hidden = await measure('terminal hidden');
await page.evaluate(() => {
  const terminal = document.querySelector('#terminal');
  const input = document.querySelector('#term-input');
  const hint = document.querySelector('#term-hint');
  const list = document.querySelector('#term-list');
  const msg = document.querySelector('#term-msg');
  if (hint) hint.textContent = '';
  if (input) input.textContent = 'git commit';
  if (list) list.classList.add('hidden');
  if (msg) msg.textContent = '';
  terminal?.classList.remove('hidden');
});
await page.waitForTimeout(200);
var visible = await measure('terminal visible');
await page.addStyleTag({ content: '#terminal { -webkit-backdrop-filter: none !important; backdrop-filter: none !important; box-shadow: none !important; }' });
await page.waitForTimeout(200);
var visibleNoBlur = await measure('terminal visible no blur/shadow');
var errors = consoleMessages.filter(m => ['error', 'pageerror'].includes(m.type));
